import React, {useEffect, useState} from 'react'
import styled from 'styled-components'
import {getUserItems} from '../WebAPI'
import {useDispatch, useSelector} from 'react-redux'


const Header = styled.div `
border:1px solid rgba(210, 210, 210, 0.8);
width:80%;
height:60px;
text-align:center;
line-height:60px;
font-size:1.2rem;
font-weight:900;
color:grey;
margin:0 auto;
box-sizing:border-box;
`

const Items = styled.div `
border-bottom:1px solid rgba(210, 210, 210, 0.8);
border-right:1px solid rgba(210, 210, 210, 0.8);
border-left:1px solid rgba(210, 210, 210, 0.8);
display:flex;
align-items:center;
font-size:0.9rem;
padding:0 20px;
height:150px;
width:80%;
margin:0 auto;
box-sizing:border-box;
`

const ItemImage = styled.div `
background-image:url(${props => props.image ? props.image : null});
background-size:contain;
background-repeat:no-repeat;
background-position:center;
width:100px;
height:100px;
margin-right:30px;
border-radius:50%;
border:1px solid transparent;
&:hover {
	cursor:pointer;
}
`

const Left = styled.div `
display:flex;
align-items:flex-start;
justify-content:center;
flex-direction:column;
`

const ItemName = styled.div `
font-weight:800;
width:200px;
margin-right:30px;
margin-top:20px;
&:hover {
	cursor:pointer;
}
`

const ItemDescription = styled.pre `
font-size:0.8rem;
width:400px;
margin-right:30px;
`

const ItemPrice = styled.div `
margin-bottom:20px;
font-size:0.9rem;
`

export default function MeItems () {
	const [userItems, setUserItems] = useState([{}])

	useEffect(() => {
		getUserItems(localStorage.getItem('userId'), setUserItems)
	},[])

	console.log(userItems)

	return (
		<>
			<Header>YOUR LISTINGS</Header>
			{ userItems.map(item =>
			<Items key={item.id}>
				<ItemImage image={item.image_1}/>
				<Left>
					<ItemName >{item.itemName}</ItemName>
					<ItemDescription>{item.description}</ItemDescription>
					<ItemPrice>{item.price}</ItemPrice>
				</Left>
			</Items>)}
		</>
	)
}
